prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?start ?startName WHERE {
  ?model tai:originalId "0b4394edaa09437d93cc54c78c0180cb" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?targetTask a bboExt:ChoreographyTask ;
              bbo:name "M5" ;
              tai:belongsTo ?choreo .

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo .
  OPTIONAL { ?start bbo:name ?startName . }

  FILTER EXISTS {
    ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?targetTask .
  }
}
ORDER BY ?startName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT 
  (COUNT(DISTINCT ?start) AS ?startCount)
  (COUNT(DISTINCT ?reachableStart) AS ?reachableStartCount)
WHERE {
  ?model tai:originalId "0b4394edaa09437d93cc54c78c0180cb" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?targetTask a bboExt:ChoreographyTask ;
              bbo:name "M5" ;
              tai:belongsTo ?choreo .

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo .

  OPTIONAL {
    ?reachableStart = ?start .
    FILTER EXISTS {
      ?reachableStart ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?targetTask .
    }
  }

  BIND(?start AS ?reachableStart)
  FILTER EXISTS {
    ?reachableStart ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?targetTask .
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?startCount ?reachableStartCount WHERE {
  {
    SELECT (COUNT(DISTINCT ?start) AS ?startCount) WHERE {
      ?model tai:originalId "0b4394edaa09437d93cc54c78c0180cb" .
      ?defs tai:belongsTo ?model .
      ?choreo tai:belongsTo ?defs .
      ?start a bboExt:StartEvent ;
             tai:belongsTo ?choreo .
    }
  }
  {
    SELECT (COUNT(DISTINCT ?reachableStart) AS ?reachableStartCount) WHERE {
      ?model tai:originalId "0b4394edaa09437d93cc54c78c0180cb" .
      ?defs tai:belongsTo ?model .
      ?choreo tai:belongsTo ?defs .

      ?targetTask a bboExt:ChoreographyTask ;
                   bbo:name "M5" ;
                   tai:belongsTo ?choreo .

      ?reachableStart a bboExt:StartEvent ;
                       tai:belongsTo ?choreo .

      FILTER EXISTS {
        ?reachableStart ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?targetTask .
      }
    }
  }
}
LIMIT 1
